org.sonar.java.checks.MultilineBlocksCur.checker_dsl:
EXISTS (`statement S_current`) {
  AND {
    EXISTS (`block B_parent`) {
      (`B_parent contains S_current`)
    },
    EXISTS (`statement S_previous`) {
      AND {
        (`S_previous is immediately before S_current in B_parent`),
        OR {
          (`S_previous is a FOR_EACH_STATEMENT, FOR_STATEMENT, WHILE_STATEMENT, or IF_STATEMENT`)
        },
        EXISTS (`statement S_block`) {
          AND {
            OR {
              AND {
                (`S_previous is a FOR_EACH_STATEMENT`),
                (`S_block is the statement body of S_previous`)
              },
              AND {
                (`S_previous is a FOR_STATEMENT`),
                (`S_block is the statement body of S_previous`)
              },
              AND {
                (`S_previous is a WHILE_STATEMENT`),
                (`S_block is the statement body of S_previous`)
              },
              AND {
                (`S_previous is an IF_STATEMENT`),
                EXISTS (`statement S_temp`) {
                  AND {
                    (`S_temp is S_previous`),
                    (`S_block is obtained by repeatedly taking the else statement if present, otherwise the then statement, from S_temp until it is not an IF_STATEMENT`)
                  }
                }
              }
            },
            (`S_block is not a BLOCK`),
            NOT {
              EXISTS (`position P_block_start`) {
                EXISTS (`position P_current_start`) {
                  AND {
                    (`P_block_start is the start position of the first token of S_block`),
                    (`P_current_start is the start position of the first token of S_current`),
                    OR {
                      AND {
                        (`P_block_start column equals P_current_start column`),
                        (`P_block_start line + 1 equals P_current_start line`)
                      },
                      AND {
                        EXISTS (`position P_previous_start`) {
                          (`P_previous_start is the start position of the first token of S_previous`)
                        },
                        (`P_block_start line equals P_previous_start line`),
                        (`P_previous_start column is less than P_current_start column`)
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

org.sonar.java.checks.unused.UnusedMetho.checker_dsl:
