  AND {
    (`M has a block`),
    (`M has at least one parameter`),
    NOT {
      OR {
        (`M is a main method`),
        EXISTS (`annotation A`) {
          NOT {
            AND {
              (`A is a @SuppressWarnings annotation`),
              FORALL (`argument ARG`) {
                (`ARG is a string literal with value "\"rawtypes\"" OR "\"unchecked\""`)
              }
            }
          }
        },
        (`M is overriding`),
        AND {
          (`M is private`),
          (`M matches the signature of writeObject(ObjectOutputStream) or readObject(ObjectInputStream)`)
        },
        AND {
          NOT { (`M's enclosing class is final`) },
          OR {
            (`M is a default method`),
            AND {
              NOT { (`M is private`) },
              OR {
                (`M's block is empty`),
                (`M's block has exactly one statement and that statement is a throw statement`)
              }
            }
          }
        },
        EXISTS (`usage U`) {
          (`U's parent is a METHOD_REFERENCE tree`)
        }
      }
    },
    EXISTS (`parameter P`) {
      AND {
        (`P's symbol has zero usages`),
        NOT {
          OR {
            (`P is annotated with javax.enterprise.event.Observes`),
            (`P is annotated with jakarta.enterprise.event.Observes`),
            EXISTS (`annotation AN`) {
              (`AN's symbol is unknown`)
            }
          }
        },
        NOT {
          AND {
            (`P's enclosing class's superclass is a subtype of "org.apache.struts.action.Action"`),
            (`P's type fully qualified name is one of: org.apache.struts.action.ActionMapping, org.apache.struts.action.ActionForm, javax.servlet.http.HttpServletRequest, javax.servlet.http.HttpServletResponse, jakarta.servlet.http.HttpServletRequest, jakarta.servlet.http.HttpServletResponse`)
          }
        },
        OR {
          NOT { (`M is overridable`) },
          AND {
            (`M is overridable`),
            (`P's name is in the set of undocumented parameters from M's Javadoc`)
          }
        },
        NOT {
          EXISTS (`unresolved identifier name N`) {
            (`N equals P's name`)
          }
        }
      }
    }
  }
}

