    EXISTS (`field F declared in class C`) {
      AND {
        (`field F is a non-static instance field`),
        (`field F is not transient AND field F's type is not serializable OR is a subtype of java.util.Collection or java.util.Map AND field F does not have any of these annotations: javax.annotation.Resource, javax.ejb.EJB, javax.inject.Inject, jakarta.inject.Inject, org.apache.wicket.spring.injection.annot.SpringBean AND field F's name is not in the set of constructor/method-injected fields for class C`),
        OR {
          AND {
            (`field F's type is a parameterized Collection/Map where all type arguments are recursively "Collection of Serializable" or serializable`),
            OR {
              AND {
                NOT { (`field F is private`) },
                NOT { (`field F's raw type implements java.io.Serializable`) }
              },
              (`field F's raw type is a non-interface subtype of java.util.Collection or java.util.Map AND field F's raw type does NOT implement java.io.Serializable`),
              EXISTS (`initializer expression IE of field F`) {
                AND {
                  (`IE is not null`),
                  NOT { (`IE is a null literal`) },
                  (`IE's type is a non-interface subtype of java.util.Collection or java.util.Map AND IE's type does NOT implement java.io.Serializable`)
                }
              },
              EXISTS (`usage identifier U of field F`) {
                AND {
                  (`U is the variable of an assignment expression`),
                  (`the expression assigned to U is a non-interface subtype of java.util.Collection or java.util.Map AND does NOT implement java.io.Serializable`)
                }
              }
            }
          },
          AND {
            NOT { (`field F's type is a parameterized Collection/Map where all type arguments are recursively "Collection of Serializable" or serializable`) },
            OR {
              (`field F has no initializer`),
              AND {
                EXISTS (`initializer expression IE of field F`) {
                  (`IE is not null`)
                },
                OR {
                  NOT { (`field F is final`) },
                  NOT { (`IE's type implements java.io.Serializable`) }
                }
              }
            }
          }
        }
      }
    }
  }
}

