          AND {
            (`REP1 is non-possessive`),
            (`REP1's quantifier is open-ended`),
            EXISTS (`BacktrackingFinder BF applied to REP1's element`) {
              OR {
                EXISTS (`atomic group AG within REP1's element`) {
                  (`BF recursively analyzes AG with a new RedosFinder ignoring full/partial match context`)
                },
                EXISTS (`nested repetition REP2 within REP1's element`) {
                  AND {
                    (`REP2 is a repetition node`),
                    OR {
                      AND {
                        (`REP2 is possessive`),
                        (`BF recursively analyzes REP2 with a new RedosFinder ignoring full/partial match context`)
                      },
                      AND {
                        (`REP2 is non-possessive`),
                        (`REP2's element and continuation have intersecting alternatives`),
                        OR {
                          AND {
                            (`REP1 is reluctant`),
                            (`found backtracking type is set to ALWAYS_EXPONENTIAL`)
                          },
                          AND {
                            (`REP1 is greedy`),
                            (`REP2's quantifier is open-ended`),
                            (`found backtracking type is set to QUADRATIC_WHEN_OPTIMIZED`)
                          },
                          AND {
                            (`REP1 is greedy`),
                            (`REP2's quantifier is not open-ended`),
                            (`found backtracking type is set to LINEAR_WHEN_OPTIMIZED`)
                          }
                        }
                      }
                    }
                  }
                },
                EXISTS (`disjunction DIS within REP1's element`) {
                  AND {
                    (`DIS is a disjunction node`),
                    (`DIS's alternatives have intersecting pairs`),
                    OR {
                      AND {
                        (`REP1 is reluctant`),
                        (`found backtracking type is set to ALWAYS_EXPONENTIAL`)
                      },
                      AND {
                        (`REP1 is greedy`),
                        (`found backtracking type is set to LINEAR_WHEN_OPTIMIZED`)
                      }
                    }
                  }
                }
              }
            }
          },
          AND {
            (`REP1's quantifier is open-ended`),
            (`REP1 can fail`),
            OR {
              EXISTS (`non-possessive repetition REP0`) {
                AND {
                  (`REP0 is in the tracked list of non-possessive repetitions`),
                  (`reachability exists from REP0 to REP1`),
                  (`sub-automaton from REP0's element to REP0's continuation can consume the sub-automaton from REP0's continuation to REP1`),
                  (`sub-automaton from REP0's continuation to REP1 is empty or intersects with sub-automaton from REP1's element to REP1's continuation`),
                  (`sub-automaton from REP0's element to REP0's continuation intersects with sub-automaton from REP1's element to REP1's continuation`),
                  (`found backtracking type is set to ALWAYS_QUADRATIC`)
