              }
            }
          },
          NOT {
            EXISTS (`throw statement TH`) {
              AND {
                (`TH is inside CB's block`),
                (`TH's expression is an identifier`),
                (`the identifier's symbol equals CP's symbol`)
              }
            }
          },
          NOT {
            EXISTS (`method invocation MI`) {
              AND {
                (`MI is inside CB's block or within method bodies called from MI up to depth 3`),
