              }
            }
          },
          NOT {
            EXISTS (`finally block FB`) {
              AND {
                (`FB is a finally block of an enclosing try statement that contains TS`),
                OR {
                  EXISTS (`method invocation MI2`) {
                    AND {
                      (`MI2 is inside FB or within method bodies called from MI2 up to depth 3`),
