org.sonar.java.checks.DeadStoreCheck.checker_dsl:
EXISTS (`method M`) {
  AND {
    (`M has a block body`),
    NOT {
      EXISTS (`try statement T`) {
        OR {
          AND {
            (`T has a finally block F`),
            EXISTS (`local variable V`) { (`V is used in F`) }
          },
          (`T has at least one resource`)
        }
      }
    },
    EXISTS (`CFG block B`) {
      EXISTS (`element E`) {
        OR {
          AND {
            (`E is an assignment expression`),
            (`E's left-hand side is an identifier I`),
            (`I's symbol is a local variable`),
            NOT { (`I's symbol is in the live variable set after E`) },
            OR {
              (`E is a simple assignment (operator "=")`),
              (`E's parent is an expression statement`)
            },
            NOT { (`I's symbol name is unresolved`) }
          },
          AND {
            (`E is a variable declaration with initializer`),
            (`E's symbol is known`),
            NOT { (`E's initializer is a usual default value`) },
            NOT { (`E's symbol is in the live variable set after E`) },
            NOT { (`E's symbol name is unresolved`) }
          },
          AND {
            (`E is a prefix increment/decrement expression`),
            (`E's parent is an expression statement`),
            (`E's operand is an identifier I`),
            (`I's symbol is a local variable`),
            NOT { (`I's symbol is in the live variable set after E`) }
          },
          AND {
            (`E is a postfix increment/decrement expression`),
            (`E's operand is an identifier I`),
            (`I's symbol is a local variable`),
            NOT { (`I's symbol is in the live variable set after E`) }
          }
        }
      }
    }
  }
}

org.sonar.java.checks.synchronization.Wr.checker_dsl:
EXISTS (`method M`) {
  AND {
    (`method M has name "writeObject", has exactly one parameter, the parameter has type "java.io.ObjectOutputStream", and has the synchronized modifier`),
    NOT {
      EXISTS (`method M2`) {
        AND {
          NOT { (`method M2 is the same method as M`) },
          (`method M2 has the synchronized modifier`)
        }
      }
    },
    NOT {
      EXISTS (`synchronized statement S`) {
        (`true`)
      }
    }
  }
}

org.sonar.java.checks.security.WebViewsF.checker_dsl:
EXISTS (`method invocation MI`) {
  AND {
    (`MI's method owner type is a subtype of "android.webkit.WebSettings"`),
    OR {
      (`MI's method name is "setAllowFileAccess"`),
      (`MI's method name is "setAllowFileAccessFromFileURLs"`),
      (`MI's method name is "setAllowContentAccess"`),
      (`MI's method name is "setAllowUniversalAccessFromFileURLs"`)
    },
    (`MI has exactly 1 parameter`),
    (`MI's first parameter type is boolean`),
    EXISTS (`argument expression AE`) {
      AND {
        (`AE is the first argument of MI`),
        (`AE resolves to a constant boolean value`),
        (`AE's resolved constant boolean value is true`)
      }
    }
  }
}

org.sonar.java.checks.OperatorPrecedence.checker_dsl:
OR {
  EXISTS (`binary expression BE`) {
    AND {
      EXISTS (`operator kind K`) { (`K is the kind of BE`) },
      EXISTS (`operator kind P`) { (`P is the operator kind at the top of the visitor's stack when BE is visited`) },
      (`the pair (P, K) is defined in the operator relation table as requiring parentheses`)
    }
  },
  EXISTS (`if statement IS`) {
    AND {
      EXISTS (`assignment expression AE`) { (`AE is the condition of IS`) },
      EXISTS (`binary expression RHS`) { (`RHS is the expression on the right-hand side of AE`) },
      (`RHS's kind is one of: EQUAL_TO, NOT_EQUAL_TO, LESS_THAN, LESS_THAN_OR_EQUAL_TO, GREATER_THAN, GREATER_THAN_OR_EQUAL_TO`)
    }
  },
  EXISTS (`conditional expression CE`) {
    AND {
      OR {
        EXISTS (`expression operand OP1`) { (`OP1 is the trueExpression of CE`) },
        EXISTS (`expression operand OP2`) { (`OP2 is the falseExpression of CE`) }
      },
      AND {
        NOT { (`OP1's tree kind is METHOD_INVOCATION`) },
        NOT { (`OP1's tree kind is IDENTIFIER`) },
        NOT { (`OP1's tree kind is MEMBER_SELECT`) },
        NOT { (`OP1's tree kind is PARENTHESIZED_EXPRESSION`) },
        NOT { (`OP1's tree kind is TYPE_CAST`) },
        NOT { (`OP1's tree kind is NEW_CLASS`) },
        NOT { (`OP1's tree kind is ARRAY_ACCESS_EXPRESSION`) },
        NOT { (`OP1's tree kind is NEW_ARRAY`) },
        NOT { (`OP1's tree kind is METHOD_REFERENCE`) },
        NOT { (`OP1 is an instance of LiteralTree`) },
        NOT { (`OP1 is an instance of UnaryExpressionTree`) },
        NOT { (`OP1 is a lambda expression and its body is an instance of LiteralTree, UnaryExpressionTree, or is of kind IDENTIFIER`) }
      }
    }
  }
}

org.sonar.java.checks.unused.UnusedLabel.checker_dsl:
EXISTS (`labeled statement LS`) {
  (`the symbol of LS has an empty usages list`)
}

org.sonar.java.checks.DoubleCheckedLocki.checker_dsl:
EXISTS (`if statement outerIf`) {
  AND {
    (`outerIf has a single then-statement`),
    (`that single then-statement is a synchronized statement syncStmt`),
    (`syncStmt's block body is not empty`),
    EXISTS (`field symbol outerField`) {
      AND {
        (`outerIf's condition is an equality (==) expression`),
        (`one operand of that equality is a null literal`),
        (`the other operand is an identifier or member select expression resolving to outerField`),
        (`outerField is owned by a type`)
      }
    },
    EXISTS (`if statement innerIf`) {
      AND {
        (`innerIf is a statement directly inside the body of syncStmt`),
        EXISTS (`field symbol innerField`) {
          AND {
            (`innerIf's condition is an equality (==) expression`),
            (`one operand of that equality is a null literal`),
            (`the other operand is an identifier or member select expression resolving to innerField`)
          }
        },
        (`innerField equals outerField`),
        (`innerIf's then-statement is a block innerBlock`),
        EXISTS (`assignment expression assignExpr`) {
          AND {
            (`assignExpr is an assignment statement inside innerBlock`),
            (`the variable part of assignExpr is an identifier or member select expression resolving to innerField`),
            EXISTS (`identifier usage idUsage`) {
              AND {
                (`idUsage is an identifier inside innerBlock`),
                (`idUsage resolves to innerField`),
                (`idUsage appears textually after assignExpr within innerBlock`)
              }
            }
          }
        }
      }
    }
  }
}

org.sonar.java.checks.security.Cryptogra.checker_dsl:
OR {
  EXISTS (`constructor call CC`) {
    AND {
      (`CC type is "java.security.spec.ECGenParameterSpec"`),
      (`CC has exactly 1 argument`),
      (`the first argument of CC is a constant string value`),
      EXISTS (`string value S`) {
        AND {
          (`S is the constant value of CC's first argument`),
          (`S matches the regex pattern "^(secp|prime|sect|c2tnb)(\\d+)"`),
          EXISTS (`integer I`) {
            AND {
              (`I is the numeric part extracted from S`),
              (`I < 224`)
            }
          }
        }
      }
    }
  },
  EXISTS (`method invocation GET_INSTANCE`) {
    AND {
      (`GET_INSTANCE method name is "getInstance" and class type is "javax.crypto.KeyGenerator" OR "java.security.KeyPairGenerator" and has exactly 1 argument and the first argument is a constant string value`),
      EXISTS (`string value ALG`) {
        AND {
          (`ALG is the constant value of GET_INSTANCE's first argument`),
          (`uppercase(ALG) is one of: RSA, DH, DIFFIEHELLMAN, DSA, AES`),
          EXISTS (`integer MIN_SIZE`) {
            AND {
              (`MIN_SIZE is the value mapped from uppercase(ALG) where RSA maps to 2048, DH maps to 2048, DIFFIEHELLMAN maps to 2048, DSA maps to 2048, AES maps to 128`),
              (`GET_INSTANCE is assigned to a variable V`),
              EXISTS (`method invocation INIT`) {
                AND {
                  (`INIT is within the same enclosing method as GET_INSTANCE`),
                  OR {
                    AND {
                      (`INIT class type is "javax.crypto.KeyGenerator"`),
                      (`INIT method name is "init"`),
                      (`INIT has exactly 1 argument`)
                    },
                    AND {
                      (`INIT class type is "java.security.KeyPairGenerator"`),
                      (`INIT method name is "initialize"`),
                      OR {
                        (`INIT has exactly 1 argument`),
                        (`INIT has exactly 2 arguments`)
                      }
                    }
                  },
                  (`the first argument of INIT is an integer literal with a constant value`),
                  EXISTS (`integer KEY_SIZE`) {
                    AND {
                      (`KEY_SIZE is the constant integer value of INIT's first argument`),
                      (`KEY_SIZE < MIN_SIZE`)
                    }
                  },
                  (`INIT is invoked on the variable V`)
                }
              }
            }
          }
        }
      }
    }
  }
}

org.sonar.java.checks.SynchronizedFieldA.checker_dsl:
OR {
  EXISTS (`synchronized statement SS`) {
    AND {
      (`SS's expression is of kind NEW_CLASS`),
      NOT {
        EXISTS (`field symbol F`) {
          (`F is the symbol of SS's expression`)
        }
      }
    }
  },
  EXISTS (`synchronized statement SS`, `field symbol F`) {
    AND {
      (`F is the symbol of SS's expression`),
      (`F is not unknown`),
      (`F's owner is a type symbol`),
      EXISTS (`assignment expression AE within SS's block`) {
        AND {
          (`AE's variable is an identifier`),
          (`the symbol of AE's variable equals F`)
        }
      }
    }
  },
  EXISTS (`synchronized statement SS`, `parameter symbol P`) {
    AND {
      (`P is the symbol of SS's expression`),
      (`P is a parameter`)
    }
  }
}
